function ensureLiveRouteLayer() {
  if (!map) return null;
  if (!layers.liveRoute) layers.liveRoute = L.layerGroup().addTo(map);
  return layers.liveRoute;
}

function drawLiveRouteTracking() {
  if (!window.L || !map || !routeTrackingPoints.length) return;
  const layer = ensureLiveRouteLayer();
  if (!layer) return;
  layer.clearLayers();
  const latest = routeTrackingPoints[routeTrackingPoints.length - 1];
  if (routeTrackingPoints.length > 1) {
    L.polyline(routeTrackingPoints, { color: "#d94c31", weight: 5, opacity: .95, dashArray: "8 6" })
      .addTo(layer)
      .bindTooltip(translateText("Live route trail"));
  }
  L.circleMarker(latest, { radius: 8, color: "#d94c31", fillColor: "#d94c31", fillOpacity: .95, weight: 3 })
    .addTo(layer)
    .bindTooltip(translateText("Live route position"));
  map.setView(latest, Math.max(map.getZoom(), 13));
}

function stopLiveRouteTracking() {
  if (routeTrackingWatchId !== null && navigator.geolocation) {
    navigator.geolocation.clearWatch(routeTrackingWatchId);
  }
  routeTrackingWatchId = null;
  ensureLiveRouteLayer()?.clearLayers();
  setVoiceResponse("Live route tracking is stopped. Your saved route points stay in this session until you refresh.", true);
}

async function startLiveRouteTracking() {
  goSection("map");
  if (!navigator.geolocation) {
    setVoiceResponse("This device does not expose GPS tracking to the browser. I can still run route-risk intelligence from the map and trade route tools.", true);
    return;
  }
  if (routeTrackingWatchId !== null) {
    setVoiceResponse("Live route tracking is already on. I will keep updating the map as the device moves.", true);
    return;
  }
  routeTrackingPoints = [];
  if (!map) renderMap();
  setVoiceResponse("Live route tracking is starting. Please allow location access if your browser asks.", true);
  try {
    await request("/api/workflow/record", {
      method: "POST",
      body: {
        module: "Map",
        action: "route.live_tracking_started",
        detail: "Live route tracking started from a voice command.",
        providerId: "maps"
      }
    });
  } catch {
    // Tracking can still run locally if evidence recording is temporarily unavailable.
  }
  routeTrackingWatchId = navigator.geolocation.watchPosition(position => {
    const point = [position.coords.latitude, position.coords.longitude];
    routeTrackingPoints.push(point);
    routeTrackingPoints = routeTrackingPoints.slice(-120);
    drawLiveRouteTracking();
    const accuracy = Math.round(position.coords.accuracy || 0);
    $("#globalAssistantStatus").textContent = translateText(`Live route tracking active. Latest accuracy: ${accuracy} meters.`);
  }, error => {
    routeTrackingWatchId = null;
    setVoiceResponse(`I could not start live route tracking: ${error.message}. Check browser location permission, then try again.`, true);
  }, {
    enableHighAccuracy: true,
    maximumAge: 5000,
    timeout: 15000
  });
}

function renderMap() {
  if (!window.L || !data) return;
  const country = activeCountry();
  const route = activeRoute();
  if (!map) {
    map = L.map("mapCanvas").setView([8, 20], 3);
    addRealMapTiles(map);
    layers.routes = L.layerGroup().addTo(map);
    layers.markers = L.layerGroup().addTo(map);
    layers.facilities = L.layerGroup().addTo(map);
    layers.liveRoute = L.layerGroup().addTo(map);
  }
  layers.routes.clearLayers();
  layers.markers.clearLayers();
  layers.facilities.clearLayers();

  data.routes.forEach(item => {
    const active = item.id === route.id;
    drawShipmentRoute(layers.routes, item, {
      order: active ? data.profile.orders?.[data.profile.orders.length - 1] : null,
      active,
      includeCurrentMarker: active,
      muted: !active
    });
  });

  data.countries.forEach(item => {
    L.marker([item.lat, item.lng])
      .addTo(layers.markers)
      .bindPopup(`<strong>${translateText(item.name)}</strong><br>${item.patients.toLocaleString()} ${translateText("patients")}<br>${item.facilities} ${translateText("facilities")}`);
  });

  [[country.lat + .7, country.lng - .8], [country.lat - .5, country.lng + .9], [country.lat + .3, country.lng + .5]].forEach((point, index) => {
    L.circleMarker(point, { radius: 6, color: "#1b8f68", fillColor: "#1b8f68", fillOpacity: .65 }).addTo(layers.facilities).bindTooltip(`${translateText("Facility")} ${index + 1}`);
  });
  map.setView([country.lat, country.lng], country.zoom);
  drawLiveRouteTracking();
  setTimeout(() => map.invalidateSize(), 100);
}

function shipmentTrackingState(route = activeRoute(), order = null) {
  const checkpoints = route?.checkpoints || [];
  const live = order?.liveTracking || {};
  const activeCheckpoint = order?.checkpoint || data?.profile?.activeCheckpoint || checkpoints[0] || "Pickup";
  const checkpointIndex = checkpoints.findIndex(checkpoint => checkpoint === activeCheckpoint);
  const safeIndex = Math.max(0, Math.min(checkpointIndex < 0 ? 0 : checkpointIndex, Math.max(0, checkpoints.length - 1)));
  const completed = checkpoints.length ? safeIndex + 1 : 1;
  const total = Math.max(1, checkpoints.length);
  const progress = Math.round((completed / total) * 100);
  const nextCheckpoint = checkpoints[Math.min(safeIndex + 1, total - 1)] || checkpoints[total - 1] || "Buyer handoff";
  const remainingStops = Math.max(0, total - completed);
  const etaHours = Math.max(2, remainingStops * 5 + 3);
  return {
    activeCheckpoint,
    safeIndex,
    completed,
    total,
    progress,
    nextCheckpoint: live.currentLocation || nextCheckpoint,
    remainingStops,
    eta: live.eta || (remainingStops ? `${etaHours}-${etaHours + 4} hrs` : "Arriving now"),
    status: live.status || order?.stage || data?.profile?.routeStage || "Tracking",
    provider: live.provider || "AgriNexus route tracker",
    source: live.source || "local-route-estimate",
    trackingNumber: live.trackingNumber || order?.trackingNumber || order?.orderNumber || "",
    livePoint: Number.isFinite(Number(live.latitude)) && Number.isFinite(Number(live.longitude)) ? [Number(live.latitude), Number(live.longitude)] : null,
    lastEvent: live.lastEvent || ""
  };
}

function shipmentMarkerIcon(label = "Shipment") {
  return L.divIcon({
    className: "shipment-tracker-marker",
    html: `<span aria-hidden="true"></span><b>${escapeHtml(translateText(label))}</b>`,
    iconSize: [112, 34],
    iconAnchor: [18, 17],
    popupAnchor: [0, -14]
  });
}

function drawShipmentRoute(layer, route = activeRoute(), { order = null, active = true, includeCurrentMarker = true, muted = false } = {}) {
  if (!window.L || !layer || !route?.points?.length) return;
  const state = shipmentTrackingState(route, order);
  const points = route.points || [];
  const currentPoint = state.livePoint || points[Math.min(state.safeIndex, points.length - 1)] || points[0];
  const completedPoints = points.slice(0, Math.min(state.safeIndex + 1, points.length));
  const remainingPoints = points.slice(Math.min(state.safeIndex, points.length - 1));
  const routeColor = active ? "#0f5f9c" : "#5f7380";
  const completedColor = active ? "#0f766e" : "#8b9aa3";
  const remainingColor = active ? "#f59e0b" : "#a5b1b8";
  if (completedPoints.length > 1) {
    L.polyline(completedPoints, {
      color: completedColor,
      weight: active ? 7 : 4,
      opacity: muted ? .55 : .95,
      lineCap: "round",
      lineJoin: "round"
    }).addTo(layer).bindTooltip(translateText("Completed shipment leg"));
  }
  if (remainingPoints.length > 1) {
    L.polyline(remainingPoints, {
      color: remainingColor,
      weight: active ? 6 : 4,
      opacity: muted ? .45 : .92,
      dashArray: active ? "12 10" : "8 10",
      lineCap: "round",
      lineJoin: "round"
    }).addTo(layer).bindTooltip(translateText("Remaining shipment leg"));
  } else if (points.length > 1) {
    L.polyline(points, { color: routeColor, weight: active ? 6 : 4, opacity: muted ? .5 : .85 }).addTo(layer);
  }
  (route.checkpoints || []).forEach((checkpoint, index) => {
    const point = points[Math.min(index, points.length - 1)];
    if (!point) return;
    const isCurrent = index === state.safeIndex;
    const isDone = index < state.safeIndex;
    L.circleMarker(point, {
      radius: isCurrent ? 9 : 6,
      color: isCurrent ? "#111827" : isDone ? completedColor : "#334155",
      fillColor: isCurrent ? "#ffffff" : isDone ? completedColor : "#ffffff",
      fillOpacity: 1,
      weight: isCurrent ? 4 : 2
    }).addTo(layer).bindPopup(`<strong>${translateText(checkpoint)}</strong><br>${translateText(isCurrent ? "Current shipment checkpoint" : isDone ? "Completed checkpoint" : "Next checkpoint")}`);
  });
  if (includeCurrentMarker && currentPoint) {
    L.marker(currentPoint, { icon: shipmentMarkerIcon("Live shipment") })
      .addTo(layer)
      .bindPopup(`<strong>${translateText("Shipment tracking")}</strong><br>${translateText(state.nextCheckpoint || state.activeCheckpoint)}<br>${translateText(`ETA: ${state.eta}`)}<br>${translateText(state.source === "live-provider" ? "Live provider GPS" : "Platform tracking")}`);
  }
}

function addLiveMapStatusControl(targetMap) {
  const state = {
    loaded: 0,
    errors: 0,
    lastLayer: "Operational map"
  };
  const control = L.control({ position: "topright" });
  control.onAdd = () => {
    const div = L.DomUtil.create("div", "live-map-status-control");
    div.innerHTML = `
      <strong>${translateText("Live map")}</strong>
      <span data-live-map-status>${translateText("Loading real map tiles")}</span>
      <small>${translateText("Grid, country lines, scale, and global view active")}</small>
    `;
    L.DomEvent.disableClickPropagation(div);
    return div;
  };
  control.addTo(targetMap);
  const update = () => {
    const label = targetMap.getContainer()?.querySelector("[data-live-map-status]");
    if (!label) return;
    const status = state.loaded
      ? `${state.loaded} ${translateText("real tile(s) loaded")} - ${translateText(state.lastLayer)}`
      : state.errors
        ? `${translateText("Tile provider retrying")} - ${state.errors} ${translateText("error(s)")}`
        : translateText("Loading real map tiles");
    label.textContent = status;
  };
  update();
  return {
    tileLoad(layerName) {
      state.loaded += 1;
      state.lastLayer = layerName || state.lastLayer;
      update();
    },
    tileError(layerName) {
      state.errors += 1;
      state.lastLayer = layerName || state.lastLayer;
      update();
    }
  };
}

function addRealMapTiles(targetMap) {
  if (!targetMap || !window.L) return {};
  if (!targetMap.getPane("countryLabels")) {
    targetMap.createPane("countryLabels");
    targetMap.getPane("countryLabels").style.zIndex = 420;
    targetMap.getPane("countryLabels").style.pointerEvents = "none";
  }
  if (!targetMap.getPane("mapGrid")) {
    targetMap.createPane("mapGrid");
    targetMap.getPane("mapGrid").style.zIndex = 430;
    targetMap.getPane("mapGrid").style.pointerEvents = "none";
  }
  const operationalLayer = L.tileLayer("https://services.arcgisonline.com/ArcGIS/rest/services/World_Street_Map/MapServer/tile/{z}/{y}/{x}", {
    maxZoom: 19,
    attribution: "Esri World Street Map"
  });
  const satelliteLayer = L.tileLayer("https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}", {
    maxZoom: 19,
    attribution: "Esri World Imagery"
  });
  const labelLayer = L.tileLayer("https://services.arcgisonline.com/ArcGIS/rest/services/Reference/World_Boundaries_and_Places/MapServer/tile/{z}/{y}/{x}", {
    maxZoom: 19,
    attribution: "Esri boundaries and places",
    pane: "countryLabels",
    opacity: .95
  });
  const streetLayer = L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", {
    maxZoom: 19,
    attribution: "OpenStreetMap contributors"
  });
  const gridLayer = createGlobalGridLayer();
  const statusControl = addLiveMapStatusControl(targetMap);
  [
    [operationalLayer, "Operational map"],
    [satelliteLayer, "Satellite imagery"],
    [labelLayer, "Country names and borders"],
    [streetLayer, "Street map"]
  ].forEach(([layer, layerName]) => {
    layer.on("tileload", () => statusControl.tileLoad(layerName));
    layer.on("tileerror", () => statusControl.tileError(layerName));
  });
  let fallbackAdded = false;
  const activateFallback = () => {
    if (fallbackAdded || targetMap.hasLayer(streetLayer)) return;
    fallbackAdded = true;
    streetLayer.addTo(targetMap);
  };
  operationalLayer.on("tileerror", activateFallback);
  satelliteLayer.on("tileerror", activateFallback);
  operationalLayer.addTo(targetMap);
  labelLayer.addTo(targetMap);
  gridLayer.addTo(targetMap);
  L.control.layers({
    "Operational map": operationalLayer,
    "Satellite imagery": satelliteLayer,
    "Street map": streetLayer
  }, {
    "Country names and borders": labelLayer,
    "Latitude/longitude grid": gridLayer
  }, { collapsed: true }).addTo(targetMap);
  L.control.scale({ metric: true, imperial: false }).addTo(targetMap);
  addGlobalMapControl(targetMap);
  return { operationalLayer, satelliteLayer, streetLayer, labelLayer, gridLayer };
}

function globalMapBounds() {
  return L.latLngBounds([[-60, -180], [80, 180]]);
}

function mapGridLabel(value, axis) {
  if (value === 0) return "0 deg";
  if (axis === "lat") return `${Math.abs(value)} deg ${value > 0 ? "N" : "S"}`;
  return `${Math.abs(value)} deg ${value > 0 ? "E" : "W"}`;
}

function createGlobalGridLayer() {
  const layer = L.layerGroup();
  const lineStyle = {
    color: "#173240",
    weight: 1,
    opacity: .28,
    interactive: false,
    pane: "mapGrid"
  };
  for (let lat = -60; lat <= 75; lat += 15) {
    L.polyline([[lat, -180], [lat, 180]], lineStyle).addTo(layer);
    L.marker([lat, -176], {
      interactive: false,
      icon: L.divIcon({
        className: "map-grid-label",
        html: mapGridLabel(lat, "lat"),
        iconSize: [58, 18],
        iconAnchor: [0, 9]
      })
    }).addTo(layer);
  }
  for (let lng = -180; lng <= 180; lng += 30) {
    L.polyline([[-60, lng], [80, lng]], lineStyle).addTo(layer);
    L.marker([78, lng], {
      interactive: false,
      icon: L.divIcon({
        className: "map-grid-label map-grid-label-lng",
        html: mapGridLabel(lng, "lng"),
        iconSize: [64, 18],
        iconAnchor: [32, 9]
      })
    }).addTo(layer);
  }
  return layer;
}

function addGlobalMapControl(targetMap) {
  const control = L.control({ position: "topleft" });
  control.onAdd = () => {
    const wrap = L.DomUtil.create("div", "leaflet-bar global-map-control");
    const button = L.DomUtil.create("button", "", wrap);
    button.type = "button";
    button.title = translateText("Zoom to global map");
    button.setAttribute("aria-label", translateText("Zoom to global map"));
    button.textContent = translateText("Global");
    L.DomEvent.disableClickPropagation(wrap);
    L.DomEvent.on(button, "click", event => {
      L.DomEvent.preventDefault(event);
      targetMap.fitBounds(globalMapBounds(), { padding: [22, 22], maxZoom: 2 });
    });
    return wrap;
  };
  control.addTo(targetMap);
}

function startAskNexusAfterLogin() {
  if (voiceDemoQuietMode) {
    disableNexusVoiceForDemo("Demo quiet mode is on. Nexus voice will stay off until you turn it back on.", { silent: true });
    return;
  }
  openAskNexus();
  voiceAutoRestart = voiceFirstMode;
  voiceStopRequested = !voiceFirstMode;
  nexusAwaitingCommand = true;
  setVoiceStatus(voiceFirstMode ? "voice-first" : "standby");
  const message = `Welcome ${userFirstName()}. Nexus is ready. Say Nexus, then tell me what you need. I will repeat it first and wait for yes.`;
  recordNexusAutonomousLearning({ type: "login-greeting", command: "Nexus ready after login" });
  setVoiceResponse(message, false, { allowVoiceFirst: false });
  [80, 360, 900, 1800].forEach(delay => {
    setTimeout(() => {
      if (!voiceDemoQuietMode && !document.hidden && voiceFirstMode && !voiceRecognition && !voiceSpeaking && !voiceStopRequested) {
        startVoiceListening();
      }
    }, delay);
  });
}

function surroundingMapBounds(route = activeRoute(), country = activeCountry()) {
  const points = [
    ...(route?.points || []),
    ...((data?.countries || []).map(item => [item.lat, item.lng])),
    [country.lat + 1.8, country.lng - 2.2],
    [country.lat - 1.6, country.lng + 2.3],
    [country.lat + 1.1, country.lng + 1.8]
  ].filter(point => Array.isArray(point) && Number.isFinite(Number(point[0])) && Number.isFinite(Number(point[1])));
  const bounds = points.length ? L.latLngBounds(points) : L.latLngBounds([[-35, -20], [36, 55]]);
  return bounds.pad(.35);
}

function fitMapToSurroundingRegion(targetMap, route = activeRoute(), country = activeCountry(), maxZoom = 5) {
  const bounds = surroundingMapBounds(route, country);
  if (bounds.isValid?.()) {
    targetMap.fitBounds(bounds, { padding: [34, 34], maxZoom });
  } else {
    targetMap.setView([3.2, 20.5], 3);
  }
}

function addOperationalCountryMarkers(targetMap, markerLayer, country = activeCountry(), { health = false } = {}) {
  const riskColor = risk => {
    const value = String(risk || "").toLowerCase();
    if (value.includes("high")) return "#d94c31";
    if (value.includes("moderate") || value.includes("elevated")) return "#d9a71d";
    return "#1b8f68";
  };
  (data.countries || []).forEach(item => {
    const active = item.id === country.id;
    const color = health ? riskColor(item.risk) : active ? "#d94c31" : "#1b8f68";
    L.circleMarker([item.lat, item.lng], {
      radius: active ? 12 : 8,
      color: active ? "#173240" : color,
      fillColor: color,
      fillOpacity: active ? .9 : .72,
      weight: active ? 4 : 2
    })
      .addTo(markerLayer)
      .bindPopup(`<strong>${translateText(item.name)}</strong><br>${item.facilities} ${translateText("facilities")}<br>${translateText(item.risk || "Monitored")} ${translateText("risk")}<br>${translateText(item.queue || "Operational area")}`);
  });
}

function addNearbyFacilityMarkers(layer, country = activeCountry(), label = "Facility") {
  [[country.lat + .7, country.lng - .8], [country.lat - .5, country.lng + .9], [country.lat + .3, country.lng + .5]].forEach((point, index) => {
    L.circleMarker(point, {
      radius: 7,
      color: "#173240",
      fillColor: "#ffffff",
      fillOpacity: 1,
      weight: 3
    }).addTo(layer).bindPopup(`<strong>${translateText(label)} ${index + 1}</strong><br>${translateText("Nearby support point")}`);
  });
}

function renderUserRealMap() {
  const canvas = $("#userMapCanvas");
  if (!canvas || !data) return;
  if (!window.L) {
    canvas.innerHTML = `<div class="user-real-map-fallback">${translateText("Map tiles are loading. Check your internet connection, then refresh this screen.")}</div>`;
    return;
  }
  if (userMap) {
    try {
      userMap.remove();
    } catch (error) {
      // Leaflet can throw if the old user-mode panel was already removed.
    }
    userMap = null;
    userMapLayers = {};
  }

  const country = activeCountry();
  const route = activeRoute();
  userMap = L.map(canvas, {
    zoomControl: true,
    attributionControl: true,
    scrollWheelZoom: true,
    tap: true,
    worldCopyJump: true,
    preferCanvas: true,
    minZoom: 1
  }).setView([3.2, 20.5], 3);
  addRealMapTiles(userMap);

  userMapLayers.route = L.layerGroup().addTo(userMap);
  userMapLayers.markers = L.layerGroup().addTo(userMap);
  userMapLayers.facilities = L.layerGroup().addTo(userMap);

  L.rectangle([[-35, -20], [36, 55]], {
    color: "#173240",
    weight: 1,
    fill: false,
    dashArray: "10 8",
    opacity: .45
  }).addTo(userMapLayers.route).bindPopup(translateText("Regional Africa operations view. Zoom or drag to inspect surrounding areas."));
  drawShipmentRoute(userMapLayers.route, route, {
    order: data.profile.orders?.[data.profile.orders.length - 1],
    active: true,
    includeCurrentMarker: true
  });

  addOperationalCountryMarkers(userMap, userMapLayers.markers, country);
  addNearbyFacilityMarkers(userMapLayers.facilities, country, "Support point");
  fitMapToSurroundingRegion(userMap, route, country, 5);
  setTimeout(() => userMap?.invalidateSize(), 120);
}

function renderUserHealthMap() {
  const canvas = $("#userHealthMapCanvas");
  if (!canvas || !data) return;
  if (!window.L) {
    canvas.innerHTML = `<div class="user-real-map-fallback">${translateText("Map tiles are loading. Check your internet connection, then refresh this screen.")}</div>`;
    return;
  }
  if (userHealthMap) {
    try {
      userHealthMap.remove();
    } catch (error) {
      // The previous user health panel may already be gone after navigation.
    }
    userHealthMap = null;
    userHealthMapLayers = {};
  }

  const country = activeCountry();
  userHealthMap = L.map(canvas, {
    zoomControl: true,
    attributionControl: true,
    scrollWheelZoom: true,
    tap: true,
    worldCopyJump: true,
    preferCanvas: true,
    minZoom: 1
  }).setView([3.2, 20.5], 3);
  addRealMapTiles(userHealthMap);

  userHealthMapLayers.region = L.layerGroup().addTo(userHealthMap);
  userHealthMapLayers.markers = L.layerGroup().addTo(userHealthMap);
  userHealthMapLayers.facilities = L.layerGroup().addTo(userHealthMap);

  L.rectangle([[-35, -20], [36, 55]], {
    color: "#173240",
    weight: 1,
    fill: false,
    dashArray: "10 8",
    opacity: .45
  }).addTo(userHealthMapLayers.region).bindPopup(translateText("Regional Africa health access view. Zoom or drag to inspect nearby areas."));

  addOperationalCountryMarkers(userHealthMap, userHealthMapLayers.markers, country, { health: true });
  addNearbyFacilityMarkers(userHealthMapLayers.facilities, country, "Care point");
  fitMapToSurroundingRegion(userHealthMap, activeRoute(), country, 5);
  setTimeout(() => userHealthMap?.invalidateSize(), 120);
}

function ruralHealthFallbackSites(country = activeCountry()) {
  const point = (latOffset, lngOffset) => ({
    lat: Number((Number(country.lat || 0) + latOffset).toFixed(4)),
    lng: Number((Number(country.lng || 0) + lngOffset).toFixed(4))
  });
  return [
    { type: "clinic", name: `${country.name} rural clinic access point`, distanceKm: 24, services: ["primary care intake", "telehealth callback"], ...point(.22, -.28) },
    { type: "mobile-clinic", name: `${country.name} mobile clinic route`, distanceKm: 41, services: ["field outreach", "vitals collection"], ...point(-.35, .44) },
    { type: "pharmacy", name: `${country.name} pharmacy support desk`, distanceKm: 18, services: ["medicine availability", "refill coordination"], ...point(.14, .36) },
    { type: "medical-supply", name: `${country.name} medical supply depot`, distanceKm: 32, services: ["PPE", "rapid tests", "wound care", "clinic equipment"], ...point(-.12, .58) }
  ];
}

function ruralHealthMapSites() {
  const guides = data.profile.ruralSymptomGuides || [];
  const clinicMatches = data.profile.ruralClinicMatches || [];
  const mobileRequests = data.profile.mobileClinicRequests || [];
  const pharmacyRequests = data.profile.pharmacyRequests || [];
  const handoffPackets = data.profile.ruralHealthHandoffPackets || [];
  const supplyRequests = data.profile.mobileClinicSupplyRequests || [];
  const supplyMatches = data.profile.mobileClinicSupplyMatches || [];
  const supplyDispatches = data.profile.mobileClinicSupplyDispatches || [];
  const sites = [
    ...clinicMatches.flatMap(item => item.clinicOptions || [item.nearestClinic]).filter(Boolean).map(item => ({ ...item, type: "clinic" })),
    ...mobileRequests.flatMap(item => item.mobileClinicOptions || [item.mobileClinic]).filter(Boolean).map(item => ({ ...item, type: "mobile-clinic" })),
    ...pharmacyRequests.flatMap(item => item.pharmacyOptions || [item.pharmacy]).filter(Boolean).map(item => ({ ...item, type: "pharmacy" })),
    ...guides.flatMap(item => [item.nearestClinic && { ...item.nearestClinic, type: "clinic" }, item.mobileClinic && { ...item.mobileClinic, type: "mobile-clinic" }, item.pharmacy && { ...item.pharmacy, type: "pharmacy" }]).filter(Boolean),
    ...handoffPackets.flatMap(item => [item.clinic && { ...item.clinic, type: "clinic" }, item.mobileClinic && { ...item.mobileClinic, type: "mobile-clinic" }, item.pharmacy && { ...item.pharmacy, type: "pharmacy" }]).filter(Boolean),
    ...supplyRequests.flatMap(item => item.supplyOptions || [item.suggestedSource]).filter(Boolean).map(item => ({ ...item, type: "medical-supply" })),
    ...supplyMatches.flatMap(item => item.supplyOptions || [item.selectedSource]).filter(Boolean).map(item => ({ ...item, type: "medical-supply" })),
    ...supplyDispatches.flatMap(item => [item.supplySource]).filter(Boolean).map(item => ({ ...item, type: "medical-supply" }))
  ];
  const seen = new Set();
  return (sites.length ? sites : ruralHealthFallbackSites()).filter(site => {
    const key = site.id || `${site.type}-${site.name}-${site.lat}-${site.lng}`;
    if (seen.has(key) || !Number.isFinite(Number(site.lat)) || !Number.isFinite(Number(site.lng))) return false;
    seen.add(key);
    return true;
  });
}

function latestRuralHealthPoint(country = activeCountry()) {
  return (data.profile.ruralSymptomGuides || [])[0]?.patientPoint
    || (data.profile.ruralClinicMatches || [])[0]?.patientPoint
    || (data.profile.mobileClinicRequests || [])[0]?.patientPoint
    || (data.profile.pharmacyRequests || [])[0]?.patientPoint
    || (data.profile.mobileClinicSupplyRequests || [])[0]?.patientPoint
    || (data.profile.mobileClinicSupplyMatches || [])[0]?.patientPoint
    || { label: country.name, lat: country.lat, lng: country.lng };
}

function ruralHealthMapLegendHtml() {
  return `
    <div class="rural-map-legend">
      <strong>${translateText("Rural health map")}</strong>
      <span><b class="legend-patient"></b>${translateText("Patient or mobile clinic")}</span>
      <span><b class="legend-clinic"></b>${translateText("Clinic")}</span>
      <span><b class="legend-mobile"></b>${translateText("Mobile clinic")}</span>
      <span><b class="legend-pharmacy"></b>${translateText("Pharmacy")}</span>
      <span><b class="legend-supply"></b>${translateText("Medical supplies")}</span>
    </div>
  `;
}

function addRuralHealthMapLegend(targetMap) {
  const control = L.control({ position: "bottomleft" });
  control.onAdd = () => {
    const div = L.DomUtil.create("div", "rural-map-legend-control");
    div.innerHTML = ruralHealthMapLegendHtml();
    L.DomEvent.disableClickPropagation(div);
    return div;
  };
  control.addTo(targetMap);
}

function drawRuralHealthNetwork(layer, originPoint, sites = [], options = {}) {
  if (!originPoint || !Number.isFinite(Number(originPoint.lat)) || !Number.isFinite(Number(originPoint.lng))) return;
  const colorByType = {
    clinic: "#1b8f68",
    "mobile-clinic": "#7c3aed",
    pharmacy: "#0f72b8",
    "medical-supply": "#c2410c"
  };
  const labelByType = {
    clinic: "Clinic option",
    "mobile-clinic": "Mobile clinic route",
    pharmacy: "Pharmacy option",
    "medical-supply": "Supply source"
  };
  L.marker([originPoint.lat, originPoint.lng])
    .addTo(layer)
    .bindPopup(`<strong>${translateText(options.originLabel || "Patient/community location")}</strong><br>${translateText(originPoint.label || activeCountry().name)}`);
  sites.forEach(site => {
    const color = colorByType[site.type] || "#173240";
    const radius = site.type === "medical-supply" ? 9 : site.type === "mobile-clinic" ? 10 : 8;
    L.circleMarker([site.lat, site.lng], {
      radius,
      color: "#173240",
      fillColor: color,
      fillOpacity: .88,
      weight: site.type === "medical-supply" ? 3 : 2
    }).addTo(layer).bindPopup(`<strong>${translateText(site.name)}</strong><br>${translateText(labelByType[site.type] || "Care point")}<br>${translateText((site.services || []).join(", ") || "rural health support")}<br>${site.distanceKm ? `${site.distanceKm} km` : translateText("distance pending")}`);
    L.polyline([[originPoint.lat, originPoint.lng], [site.lat, site.lng]], {
      color,
      weight: site.type === "medical-supply" ? 5 : 3,
      opacity: site.type === "medical-supply" ? .88 : .62,
      dashArray: site.type === "mobile-clinic" ? "8 7" : site.type === "medical-supply" ? "" : "4 8",
      lineCap: "round",
      lineJoin: "round"
    }).addTo(layer).bindTooltip(translateText(site.type === "medical-supply" ? "Supply route" : labelByType[site.type] || "Care route"));
  });
}

function renderRuralHealthAccessMap() {
  const canvas = $("#ruralHealthAccessMapCanvas");
  if (!canvas || !data) return;
  if (!window.L) {
    canvas.innerHTML = `<div class="user-real-map-fallback">${translateText("Map tiles are loading. Check your internet connection, then refresh this screen.")}</div>`;
    return;
  }
  if (ruralHealthAccessMap) {
    try {
      ruralHealthAccessMap.remove();
    } catch (error) {
      // The previous health map can disappear during section re-render.
    }
    ruralHealthAccessMap = null;
  }
  if (canvas._leaflet_id) canvas.replaceWith(canvas.cloneNode(false));
  const target = $("#ruralHealthAccessMapCanvas");
  const country = activeCountry();
  const latestPoint = latestRuralHealthPoint(country);
  ruralHealthAccessMap = L.map(target, {
    zoomControl: true,
    attributionControl: true,
    scrollWheelZoom: true,
    tap: true,
    worldCopyJump: true,
    preferCanvas: true,
    minZoom: 1
  }).setView([latestPoint.lat, latestPoint.lng], 7);
  addRealMapTiles(ruralHealthAccessMap);
  addRuralHealthMapLegend(ruralHealthAccessMap);
  const layer = L.layerGroup().addTo(ruralHealthAccessMap);
  const sites = ruralHealthMapSites();
  drawRuralHealthNetwork(layer, latestPoint, sites);
  addOperationalCountryMarkers(ruralHealthAccessMap, layer, country, { health: true });
  const bounds = L.latLngBounds([[latestPoint.lat, latestPoint.lng], ...sites.map(site => [site.lat, site.lng])]);
  if (bounds.isValid?.()) ruralHealthAccessMap.fitBounds(bounds.pad(.45), { maxZoom: 8, padding: [30, 30] });
  else fitMapToSurroundingRegion(ruralHealthAccessMap, activeRoute(), country, 5);
  setTimeout(() => ruralHealthAccessMap?.invalidateSize(), 160);
}

